{
  "learning_outcomes": [
    {
      "unit_name": "Physical World and Measurement",
      "chapter_name": "Units and Measurements",
      "topic": "Need for measurement; Units of measurement; Systems of units",
      "outcomes": [
        "Understand the need for measurement, systems of units, SI units (fundamental and derived), significant figures, uncertainty determination, dimensions of physical quantities, and dimensional analysis."
      ]
    },
    {
      "unit_name": "Kinematics",
      "chapter_name": "Motion in a Straight Line",
      "topic": "Frame of reference; Motion in a straight line",
      "outcomes": [
        "Apply elementary concepts of differentiation and integration to describe motion, distinguish between uniform/non-uniform motion, calculate average/instantaneous velocity, and use relations for uniformly accelerated motion (graphical/calculus)."
      ]
    },
    {
      "unit_name": "Kinematics",
      "chapter_name": "Motion in a Plane",
      "topic": "Scalar and vector quantities; Position and displacement vectors",
      "outcomes": [
        "Master general vectors, notations, equality, multiplication by real numbers, addition/subtraction of vectors, unit vectors, resolution into rectangular components, scalar/vector products, projectile motion, uniform circular motion."
      ]
    },
    {
      "unit_name": "Laws of Motion",
      "chapter_name": "Laws of Motion",
      "topic": "Intuitive concept of force; Inertia",
      "outcomes": [
        "Understand Newton's laws (1st, 2nd with momentum/impulse, 3rd), conservation of linear momentum, equilibrium of concurrent forces, friction types, and dynamics of uniform circular motion."
      ]
    },
    {
      "unit_name": "Work, Energy and Power",
      "chapter_name": "Work, Energy and Power",
      "topic": "Work done by constant/variable force; Kinetic energy",
      "outcomes": [
        "Apply the work-energy theorem, understand power, potential energy (including springs), conservative/non-conservative forces, motion in vertical circles, and elastic/inelastic collisions."
      ]
    },
    {
      "unit_name": "Motion of System of Particles and Rigid Body",
      "chapter_name": "System of Particles and Rotational Motion",
      "topic": "Centre of mass: Two-particle system, Rigid body (uniform rod)",
      "outcomes": [
        "Analyze momentum conservation, centre of mass motion, torque, angular momentum, equilibrium of rigid bodies, rotational equations, comparison with linear motion, moment of inertia, and radius of gyration."
      ]
    },
    {
      "unit_name": "Gravitation",
      "chapter_name": "Gravitation",
      "topic": "Kepler's laws of planetary motion",
      "outcomes": [
        "Apply the universal law of gravitation, understand variation in acceleration due to gravity, gravitational potential energy/potential, escape speed, orbital velocity, and satellite energy."
      ]
    },
    {
      "unit_name": "Properties of Bulk Matter",
      "chapter_name": "Mechanical Properties of Solids",
      "topic": "Elasticity; Stress-strain relationship",
      "outcomes": [
        "Understand Hooke's law, Young’s modulus, bulk/shear moduli (qualitative), Poisson's ratio, elastic energy, and applications of elastic behavior."
      ]
    },
    {
      "unit_name": "Properties of Bulk Matter",
      "chapter_name": "Mechanical Properties of Fluids",
      "topic": "Pressure due to fluid column; Pascal's law",
      "outcomes": [
        "Analyze viscosity, Stokes' law, terminal velocity, streamline/turbulent flow, Bernoulli's theorem (Torricelli/dynamic lift), surface tension/energy, angle of contact, and excess pressure applications."
      ]
    },
    {
      "unit_name": "Properties of Bulk Matter",
      "chapter_name": "Thermal Properties of Matter",
      "topic": "Heat, Temperature; Thermal expansion (solids, liquids, gases)",
      "outcomes": [
        "Understand specific heat capacity, calorimetry, latent heat, modes of heat transfer (conduction/convection/radiation), thermal conductivity, and blackbody radiation concepts."
      ]
    },
    {
      "unit_name": "Thermodynamics",
      "chapter_name": "Thermodynamics",
      "topic": "Thermal equilibrium; Zeroth law of thermodynamics",
      "outcomes": [
        "Distinguish heat, work, internal energy; apply First and Second laws, understand state variables/equations of state, isothermal/adiabatic processes, reversible/irreversible/cyclic processes."
      ]
    },
    {
      "unit_name": "Behaviour of Perfect Gases and Kinetic Theory of Gases",
      "chapter_name": "Kinetic Theory",
      "topic": "Equation of state; Work done in compressing gas",
      "outcomes": [
        "Apply kinetic theory assumptions, understand pressure concept, temperature interpretation (RMS speed), degrees of freedom, equipartition law, specific heats, mean free path, and Avogadro's number."
      ]
    },
    {
      "unit_name": "Oscillations and Waves",
      "chapter_name": "Oscillations",
      "topic": "Periodic motion: Time period, Frequency",
      "outcomes": [
        "Describe periodic functions, Simple Harmonic Motion (S.H.M), uniform circular motion relations, phase, loaded spring oscillations, energy in S.H.M., and simple pendulum time period."
      ]
    },
    {
      "unit_name": "Oscillations and Waves",
      "chapter_name": "Waves",
      "topic": "Wave motion: Transverse and longitudinal waves",
      "outcomes": [
        "Analyze speed of travelling waves, displacement relations, superposition principle, reflection, standing waves (strings/pipes), harmonics, and beats."
      ]
    },
    {
      "unit_name": "Unit–I Electrostatics",
      "chapter_name": "Chapter–1: Electric Charges and Fields",
      "topic": "Electric charges and Conservation of charge",
      "outcomes": [
        "Apply Coulomb's law, superposition principle for multiple/continuous charges, understand electric fields (point/dipole), torque on dipoles, Gauss's theorem applications."
      ]
    },
    {
      "unit_name": "Unit–I Electrostatics",
      "chapter_name": "Chapter–2: Electrostatic Potential and Capacitance",
      "topic": "Electric potential, potential difference, equipotential surfaces",
      "outcomes": [
        "Calculate electric potential/energy for various charge distributions, understand conductors/insulators/dielectrics/polarization, capacitance concepts, series/parallel combinations."
      ]
    },
    {
      "unit_name": "Unit-II Current Electricity",
      "chapter_name": "Chapter–3: Current Electricity",
      "topic": "Electric current and drift velocity",
      "outcomes": [
        "Understand Ohm's law, resistivity/conductivity/temperature dependence, internal resistance/emf, cell combinations, Kirchhoff's rules, Wheatstone bridge."
      ]
    },
    {
      "unit_name": "Unit-III Magnetic Effects of Current and Magnetism",
      "chapter_name": "Chapter–4: Moving Charges and Magnetism",
      "topic": "Magnetic field concepts",
      "outcomes": [
        "Apply Biot-Savart/Ampere's laws, calculate forces on charges/conductors, understand torque on loops, magnetic dipole moment, moving coil galvanometer conversions."
      ]
    },
    {
      "unit_name": "Unit-III Magnetic Effects of Current and Magnetism",
      "chapter_name": "Chapter–5: Magnetism and Matter",
      "topic": "Bar magnet properties",
      "outcomes": [
        "Understand bar magnets as solenoids, magnetic field intensity (qualitative), torque on dipoles, classification of magnetic materials."
      ]
    },
    {
      "unit_name": "Unit-IV Electromagnetic Induction and Alternating Currents",
      "chapter_name": "Chapter–6: Electromagnetic Induction",
      "topic": "",
      "outcomes": [
        "Apply Faraday's laws, Lenz's law, understand self/mutual induction."
      ]
    },
    {
      "unit_name": "Unit-IV Electromagnetic Induction and Alternating Currents",
      "chapter_name": "Chapter–7: Alternating Current",
      "topic": "",
      "outcomes": [
        "Analyze peak/RMS values, reactance/impedance in LCR circuits (phasors), resonance, power factor/wattless current, AC generators and transformers."
      ]
    },
    {
      "unit_name": "Unit–V Electromagnetic Waves",
      "chapter_name": "Chapter–8: Electromagnetic Waves",
      "topic": "",
      "outcomes": [
        "Understand displacement current, characteristics/transverse nature of EM waves, and the electromagnetic spectrum."
      ]
    },
    {
      "unit_name": "Unit–VI Optics",
      "chapter_name": "Chapter–9: Ray Optics and Optical Instruments",
      "topic": "",
      "outcomes": [
        "Apply laws of reflection/refraction, mirror/lens formulas, total internal reflection (optical fibers), prism refraction, magnification/power, optical instruments."
      ]
    },
    {
      "unit_name": "Unit–VI Optics",
      "chapter_name": "Chapter–10: Wave Optics",
      "topic": "",
      "outcomes": [
        "Apply Huygen's principle to reflection/refraction, understand interference (Young's experiment), diffraction (single slit)."
      ]
    },
    {
      "unit_name": "Unit–VII Dual Nature of Radiation and Matter",
      "chapter_name": "Chapter–11: Dual Nature of Radiation and Matter",
      "topic": "",
      "outcomes": [
        "Understand photoelectric effect (Einstein's equation), particle nature of light, matter waves (de-Broglie relation)."
      ]
    },
    {
      "unit_name": "Unit-VIII Atoms and Nuclei",
      "chapter_name": "Chapter–12: Atoms",
      "topic": "",
      "outcomes": [
        "Understand Rutherford's model, Bohr model (radius/velocity/energy), hydrogen line spectra."
      ]
    },
    {
      "unit_name": "Unit-VIII Atoms and Nuclei",
      "chapter_name": "Chapter–13: Nuclei",
      "topic": "",
      "outcomes": [
        "Understand nuclear composition/size, mass-energy relation, binding energy per nucleon, fission/fusion."
      ]
    },
    {
      "unit_name": "Unit–IX Electronic Devices",
      "chapter_name": "Chapter–14: Semiconductor Electronics: Materials, Devices and Simple Circuits",
      "topic": "",
      "outcomes": [
        "Understand energy bands (conductors/semiconductors), intrinsic/extrinsic semiconductors, p-n junction diode characteristics, rectification."
      ]
    }
  ]
}
